"""Regression test for HSV color percentage parsing bug.

This test demonstrates the bug where HSV colors specified with percentage values
incorrectly scale the hue channel to 255 instead of 359.

The bug was that percentage values were always scaled using 255, but hue in HSV
color space should be 0-359 degrees. So:
- hsv(100%, 100%, 100%) should have hue 359, not hue 255
- hsv(50%, 50%, 50%) should have hue ~179, not hue ~127
"""

import pytest
from PyQt5.QtGui import QColor


class HsvColorParser:
    """Buggy HSV color parser that scales hue to 255 instead of 359."""

    def _parse_value_buggy(self, val: str) -> int:
        """Parse color value with the bug - always scales to 255."""
        try:
            return int(val)
        except ValueError:
            pass

        # BUG: Always uses 255.0 as multiplier, even for hue
        # This returns immediately for percentages without the intermediate mult assignment
        if val.endswith('%'):
            val = val[:-1]
            return int(float(val) * 255.0 / 100.0)

        mult = 255.0
        try:
            return int(float(val) * mult)
        except ValueError:
            raise ValueError(f"must be a valid color value: {val}")

    def _parse_value_fixed(self, kind: str, val: str) -> int:
        """Parse color value with the fix - scales hue to 359."""
        try:
            return int(val)
        except ValueError:
            pass

        # FIXED: Use 359 for hue, 255 for other channels
        mult = 359.0 if kind == 'h' else 255.0
        if val.endswith('%'):
            val = val[:-1]
            mult = mult / 100

        try:
            return int(float(val) * mult)
        except ValueError:
            raise ValueError(f"must be a valid color value: {val}")

    def parse_hsv_buggy(self, h_str: str, s_str: str, v_str: str):
        """Parse HSV color with the buggy implementation."""
        h = self._parse_value_buggy(h_str)
        s = self._parse_value_buggy(s_str)
        v = self._parse_value_buggy(v_str)
        return (h, s, v)

    def parse_hsv_fixed(self, h_str: str, s_str: str, v_str: str):
        """Parse HSV color with the fixed implementation."""
        h = self._parse_value_fixed('h', h_str)
        s = self._parse_value_fixed('s', s_str)
        v = self._parse_value_fixed('v', v_str)
        return (h, s, v)

    def parse_hsva_buggy(self, h_str: str, s_str: str, v_str: str, a_str: str):
        """Parse HSVA color with the buggy implementation."""
        h, s, v = self.parse_hsv_buggy(h_str, s_str, v_str)
        a = self._parse_value_buggy(a_str)
        return (h, s, v, a)

    def parse_hsva_fixed(self, h_str: str, s_str: str, v_str: str, a_str: str):
        """Parse HSVA color with the fixed implementation."""
        h, s, v = self.parse_hsv_fixed(h_str, s_str, v_str)
        a = self._parse_value_fixed('a', a_str)
        return (h, s, v, a)


class TestHsvColorPercentageParsing:
    """Test HSV color percentage parsing for the bug."""

    def setup_method(self):
        """Set up the parser for each test."""
        self.parser = HsvColorParser()

    def test_hsv_100_percent_hue_buggy_vs_fixed(self):
        """Test that 100% hue differs between buggy (255) and fixed (359)."""
        h_buggy, s_buggy, v_buggy = self.parser.parse_hsv_buggy('100%', '100%', '100%')
        h_fixed, s_fixed, v_fixed = self.parser.parse_hsv_fixed('100%', '100%', '100%')

        # The key difference: hue scales incorrectly in buggy version
        assert h_buggy == 255, "Buggy parser: 100% hue should be 255"
        assert h_fixed == 359, "Fixed parser: 100% hue should be 359"
        assert h_buggy != h_fixed, "Hue values differ between buggy and fixed"

    def test_hsv_50_percent_hue_buggy_vs_fixed(self):
        """Test that 50% hue differs between buggy (~127) and fixed (~179)."""
        h_buggy, s_buggy, v_buggy = self.parser.parse_hsv_buggy('50%', '50%', '50%')
        h_fixed, s_fixed, v_fixed = self.parser.parse_hsv_fixed('50%', '50%', '50%')

        assert h_buggy == 127, "Buggy parser: 50% hue should be 127"
        assert h_fixed == 179, "Fixed parser: 50% hue should be 179"
        assert h_buggy != h_fixed, "Hue values differ between buggy and fixed"

    def test_hsva_100_percent_hue_buggy_vs_fixed(self):
        """Test that HSVA with 100% hue differs between buggy and fixed."""
        h_buggy, s_buggy, v_buggy, a_buggy = self.parser.parse_hsva_buggy(
            '100%', '100%', '100%', '100%'
        )
        h_fixed, s_fixed, v_fixed, a_fixed = self.parser.parse_hsva_fixed(
            '100%', '100%', '100%', '100%'
        )

        assert h_buggy == 255, "Buggy HSVA: 100% hue should be 255"
        assert h_fixed == 359, "Fixed HSVA: 100% hue should be 359"
        assert h_buggy != h_fixed, "HSVA hue values differ"

    def test_hsva_50_percent_hue_buggy_vs_fixed(self):
        """Test that HSVA with 50% hue differs between buggy and fixed."""
        h_buggy, _, _, _ = self.parser.parse_hsva_buggy(
            '50%', '50%', '50%', '50%'
        )
        h_fixed, _, _, _ = self.parser.parse_hsva_fixed(
            '50%', '50%', '50%', '50%'
        )

        assert h_buggy == 127, "Buggy HSVA: 50% hue should be 127"
        assert h_fixed == 179, "Fixed HSVA: 50% hue should be 179"
        assert h_buggy != h_fixed, "HSVA hue values differ"

    def test_hue_scaling_bug_example_1(self):
        """Demonstrate the bug: hsv(100%, 100%, 100%) vs hsv(359, 255, 255)."""
        h_buggy_pct, s_buggy_pct, v_buggy_pct = self.parser.parse_hsv_buggy(
            '100%', '100%', '100%'
        )
        h_abs, s_abs, v_abs = self.parser.parse_hsv_buggy('359', '255', '255')

        # With the bug, these should produce different hue values
        # because 100% gets scaled to 255, not 359
        assert h_buggy_pct == 255, "100% hue scales to 255 with bug"
        assert h_abs == 359, "Absolute 359 stays 359"
        assert h_buggy_pct != h_abs, (
            "Bug: hsv(100%, 100%, 100%) has hue 255 "
            "but hsv(359, 255, 255) has hue 359"
        )

    def test_hue_scaling_bug_example_2(self):
        """Demonstrate the bug: hsv(50%, 50%, 50%) vs hsv(179, 127, 127)."""
        h_buggy_pct, _, _ = self.parser.parse_hsv_buggy('50%', '50%', '50%')
        h_fixed_approx, _, _ = self.parser.parse_hsv_fixed('50%', '50%', '50%')

        # With the bug, 50% hue is 127
        assert h_buggy_pct == 127, "50% hue scales to 127 with bug"
        # With the fix, 50% hue is 179 (50% of 359)
        assert h_fixed_approx == 179, "50% hue should scale to 179 when fixed"

    def test_percentage_values_various(self):
        """Test various percentage values to demonstrate the scaling bug."""
        test_cases = [
            ('0%', 0, 0),           # 0% -> (0, 0)
            ('25%', 63, 89),        # 25% -> (63 buggy, 89 fixed)
            ('50%', 127, 179),      # 50% -> (127 buggy, 179 fixed)
            ('75%', 191, 269),      # 75% -> (191 buggy, 269 fixed)
            ('100%', 255, 359),     # 100% -> (255 buggy, 359 fixed)
        ]

        for percentage, expected_buggy, expected_fixed in test_cases:
            h_buggy, _, _ = self.parser.parse_hsv_buggy(percentage, '0%', '0%')
            h_fixed, _, _ = self.parser.parse_hsv_fixed(percentage, '0%', '0%')

            assert h_buggy == expected_buggy, (
                f"Buggy: {percentage} hue should be {expected_buggy}, got {h_buggy}"
            )
            assert h_fixed == expected_fixed, (
                f"Fixed: {percentage} hue should be {expected_fixed}, got {h_fixed}"
            )

    def test_absolute_values_unchanged(self):
        """Test that absolute values produce identical results in both versions."""
        test_values = ['0', '90', '180', '270', '359']

        for h_val in test_values:
            h_buggy, s_buggy, v_buggy = self.parser.parse_hsv_buggy(h_val, '128', '200')
            h_fixed, s_fixed, v_fixed = self.parser.parse_hsv_fixed(h_val, '128', '200')

            assert h_buggy == h_fixed == int(h_val), (
                f"Absolute hue value {h_val} should be identical"
            )
            assert s_buggy == s_fixed == 128, "Absolute saturation should be identical"
            assert v_buggy == v_fixed == 200, "Absolute value should be identical"


if __name__ == '__main__':
    pytest.main([__file__, '-v'])
